#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a Hexi::file_buffer object with the given file path
    Hexi::file_buffer buffer(file_path);

    // Check if the file buffer is valid using the boolean operator
    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Create a vector to store the read data with the requested size
    std::vector<uint8_t> data(bytes_to_read);

    // Use the read method of the file_buffer to read data into the vector
    buffer.read(data.data(), bytes_to_read);

    // Return the vector containing the read data
    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a Hexi::file_buffer object with the given file path
    Hexi::file_buffer buffer(file_path);

    // Check if the file buffer is valid using the boolean operator
    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Create a vector to store the preview data with the requested size
    std::vector<uint8_t> data(bytes_to_preview);

    // Use the copy method of the file_buffer to preview data without advancing the read pointer
    buffer.copy(data.data(), bytes_to_preview);

    // Return the vector containing the previewed data
    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a Hexi::file_buffer object with the given file path
    Hexi::file_buffer buffer(file_path);

    // Check if the file buffer is valid using the boolean operator
    if (!buffer) {
        return; // Return early if file cannot be opened
    }

    // Use the write method of the file_buffer to write data from the vector
    buffer.write(data.data(), data.size());
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a Hexi::file_buffer object with the given file path
    Hexi::file_buffer buffer(file_path);

    // Check if the file buffer is valid using the boolean operator
    if (!buffer) {
        return 0; // Return 0 if file cannot be opened
    }

    // Use the size method of the file_buffer to get the readable data size
    return buffer.size();
}
