#include <cstdint>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Check if requested bytes exceed available data
    size_t available_bytes = buffer.size();
    size_t preview_bytes = (bytes_to_preview > available_bytes) ? available_bytes : bytes_to_preview;

    // Create destination buffer with appropriate size
    std::vector<uint8_t> destination_buffer(preview_bytes);

    // Use buffer's copy function to copy data without advancing read pointer
    buffer.copy(destination_buffer.data(), preview_bytes);

    // Return the destination buffer containing previewed data
    return destination_buffer;
}
```

