```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Create a buffer_adaptor from the writer's buffer
    hexi::pmc::buffer_adaptor<decltype(writer.buffer())> adaptor(writer.buffer());

    // Use the varint_encode function from hexi::detail namespace
    return hexi::detail::varint_encode<T>(adaptor, value);
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    // Create a buffer_adaptor from the reader's buffer
    hexi::pmc::buffer_adaptor<decltype(reader.buffer())> adaptor(reader.buffer());

    // Use the varint_decode function from hexi::detail namespace
    return hexi::detail::varint_decode<T>(adaptor);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer (vector) to hold the encoded data
    std::vector<std::uint8_t> buffer;

    // Create a buffer_adaptor for the vector buffer
    hexi::pmc::buffer_adaptor<std::vector<std::uint8_t>> adaptor(buffer);

    // Create binary_stream_writer and binary_stream_reader using the adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Encode the value using the writer
    encode_varint(writer, original_value);

    // Decode the value using the reader
    T decoded_value = decode_varint<T>(reader);

    // Compare the decoded value with the original value
    return original_value == decoded_value;
}
```

## Key Implementation Points:

1. **encode_varint**: 
   - Creates a `buffer_adaptor` from the writer's buffer
   - Uses `hexi::detail::varint_encode` function with the adaptor and value
   - Returns the number of bytes written as specified in the reference materials

2. **decode_varint**:
   - Creates a `buffer_adaptor` from the reader's buffer  
   - Uses `hexi::detail::varint_decode` function with the adaptor
   - Returns the decoded value as specified

3. **encode_decode_roundtrip**:
   - Creates a vector buffer to hold encoded data
   - Creates a `buffer_adaptor` for the vector buffer
   - Creates both writer and reader using the same adaptor
   - Encodes and decodes the value, then compares results
   - Returns true if values match, false otherwise

The implementation follows the exact specifications provided, using the appropriate Hexi library functions and adhering to the varint encoding/decoding patterns demonstrated in the reference materials.

