    std::size_t available_space = write_adaptor.free();

    // Write data to buffer using write() method
    write_adaptor.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check readable size using size() method
    std::size_t readable_size = read_adaptor.size();

    // Read data back using read() method
    std::vector<uint8_t> output_data(readable_size);
    read_adaptor.read(output_data.data(), readable_size);

    return output_data;
}

